package com.taskflow.dto;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("Auth DTO Validation")
class AuthDtoValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    // ========== RegisterRequest ==========

    @Nested
    @DisplayName("RegisterRequest")
    class RegisterRequestTests {

        // --- Red/Green: Happy Path ---

        @Test
        @DisplayName("should pass validation with valid input")
        void shouldPassValidationWithValidInput() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("Valid User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        // --- Username Validation ---

        @Test
        @DisplayName("should fail validation when username is null")
        void shouldFailValidationWhenUsernameIsNull() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername(null);
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should fail validation when username is too short (2 chars)")
        void shouldFailValidationWhenUsernameIsTooShort() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("ab");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should pass validation when username is exactly 3 chars")
        void shouldPassValidationWhenUsernameIsExactly3Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("abc");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("should pass validation when username is exactly 50 chars")
        void shouldPassValidationWhenUsernameIsExactly50Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("a".repeat(50));
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("should fail validation when username is 51 chars")
        void shouldFailValidationWhenUsernameIs51Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("a".repeat(51));
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should fail validation when username contains special characters")
        void shouldFailValidationWhenUsernameContainsSpecialCharacters() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("user@name!");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should fail validation when username contains spaces")
        void shouldFailValidationWhenUsernameContainsSpaces() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("user name");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should pass validation when username contains underscore")
        void shouldPassValidationWhenUsernameContainsUnderscore() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("user_name");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("should pass validation when username contains digits")
        void shouldPassValidationWhenUsernameContainsDigits() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("user123");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        // --- Password Validation ---

        @Test
        @DisplayName("should fail validation when password is null")
        void shouldFailValidationWhenPasswordIsNull() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword(null);
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("password"));
        }

        @Test
        @DisplayName("should fail validation when password is too short (7 chars)")
        void shouldFailValidationWhenPasswordIsTooShort() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("1234567");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("password"));
        }

        @Test
        @DisplayName("should pass validation when password is exactly 8 chars")
        void shouldPassValidationWhenPasswordIsExactly8Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("12345678");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        // --- DisplayName Validation ---

        @Test
        @DisplayName("should fail validation when displayName is null")
        void shouldFailValidationWhenDisplayNameIsNull() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName(null);

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("displayName"));
        }

        @Test
        @DisplayName("should fail validation when displayName is blank")
        void shouldFailValidationWhenDisplayNameIsBlank() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("   ");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("displayName"));
        }

        @Test
        @DisplayName("should fail validation when displayName exceeds 100 chars")
        void shouldFailValidationWhenDisplayNameExceeds100Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("D".repeat(101));

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("displayName"));
        }

        @Test
        @DisplayName("should pass validation when displayName is exactly 100 chars")
        void shouldPassValidationWhenDisplayNameIsExactly100Chars() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("D".repeat(100));

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("should pass validation when displayName is 1 char")
        void shouldPassValidationWhenDisplayNameIs1Char() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("A");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ========== LoginRequest ==========

    @Nested
    @DisplayName("LoginRequest")
    class LoginRequestTests {

        @Test
        @DisplayName("should have username and password fields")
        void shouldHaveUsernameAndPasswordFields() {
            LoginRequest request = new LoginRequest();
            request.setUsername("testuser");
            request.setPassword("password123");

            assertThat(request.getUsername()).isEqualTo("testuser");
            assertThat(request.getPassword()).isEqualTo("password123");
        }
    }

    // ========== LoginResponse ==========

    @Nested
    @DisplayName("LoginResponse")
    class LoginResponseTests {

        @Test
        @DisplayName("should have token and expiresIn fields")
        void shouldHaveTokenAndExpiresInFields() {
            LoginResponse response = new LoginResponse();
            response.setToken("jwt.token.here");
            response.setExpiresIn(86400L);

            assertThat(response.getToken()).isEqualTo("jwt.token.here");
            assertThat(response.getExpiresIn()).isEqualTo(86400L);
        }

        // --- Contract Test ---

        @Test
        @DisplayName("should match contract: expiresIn is long type for seconds")
        void shouldMatchContractExpiresInIsLongType() {
            LoginResponse response = new LoginResponse();
            response.setExpiresIn(86400L);

            assertThat(response.getExpiresIn()).isEqualTo(86400L);
        }
    }
}

